public class GradeCalculator {
    public static void main(String[] args) {
        int korean = 85;
        int english = 92;
        int math = 78;

        // 1. 평균 계산 (정수 나눗셈 주의!)
        double average = (korean + english + math) / 3.0;
        System.out.println("평균: " + average);

        // 2. 학점 판정
        String grade;
        if (average >= 90) {
            grade = "A";
        } else if (average >= 80) {
            grade = "B";
        } else if (average >= 70) {
            grade = "C";
        } else {
            grade = "F";
        }
        System.out.println("학점: " + grade);

        // 3. 과목별 출력
        int[] scores = {korean, english, math};
        String[] subjects = {"국어", "영어", "수학"};

        for (int i = 0; i < scores.length; i++) {
            System.out.println(subjects[i] + ": " + scores[i] + "점");
        }
    }
}

