public class ScoreAnalyzer {
    public static void main(String[] args) {
        int[] scores = {78, 92, 85, 63, 91, 88, 76, 95, 70, 82};

        // 1. 최고점, 최저점 찾기
        int max = scores[0];
        int min = scores[0];
        int sum = 0;

        for (int score : scores) {
            if (score > max) max = score;
            if (score < min) min = score;
            sum += score;
        }

        double average = sum / (double) scores.length;

        // 2. 결과 출력 (StringBuilder 활용)
        StringBuilder sb = new StringBuilder();
        sb.append("=== 성적 분석 결과 ===\n");
        sb.append("학생 수: ").append(scores.length).append("명\n");
        sb.append("최고점: ").append(max).append("점\n");
        sb.append("최저점: ").append(min).append("점\n");
        sb.append(String.format("평균: %.1f점\n", average));

        System.out.println(sb.toString());
    }
}

