static String determineGrade(double average) {
    if (average >= 90) return "A";
    if (average >= 80) return "B";
    return "C";
}

static void printStudentReport(String name, int[] scores) {
    double avg = calculateAverage(scores);
    String grade = determineGrade(avg);
    System.out.println(name + " - 평균: " + avg + ", 학점: " + grade);
}

