public class Student {
    private String name;
    private int age;

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;                    // 같은 객체면 true
        if (o == null || getClass() != o.getClass()) return false;  // 타입 확인
        Student student = (Student) o;
        return age == student.age && name.equals(student.name);     // 값 비교
    }

    @Override
    public int hashCode() {
        return Objects.hash(name, age);   // equals에 사용한 필드로 해시코드 생성
    }
}

