// 자식 1: 정규직 (연봉 + 보너스)
public class FullTimeEmployee extends Employee {
    private double bonusRate;

    public FullTimeEmployee(String name, String id, double salary, double bonusRate) {
        super(name, id, salary);
        this.bonusRate = bonusRate;
    }

    @Override
    public double calculatePay() {
        return super.calculatePay() * (1 + bonusRate);
    }
}

// 자식 2: 계약직 (시급 × 시간)
public class ContractEmployee extends Employee {
    private int hoursWorked;

    public ContractEmployee(String name, String id, double hourlyRate, int hours) {
        super(name, id, hourlyRate);
        this.hoursWorked = hours;
    }

    @Override
    public double calculatePay() {
        return super.calculatePay() * hoursWorked;
    }
}

