public class PayrollSystem {
    // 다형성: Employee 타입이면 무엇이든 처리
    static void processPayroll(Employee[] employees) {
        double totalPay = 0;
        for (Employee emp : employees) {
            double pay = emp.calculatePay();   // 동적 바인딩!
            System.out.println(emp.getName() + ": " + pay + "원");
            totalPay += pay;
        }
        System.out.println("총 급여: " + totalPay + "원");
    }

    public static void main(String[] args) {
        Employee[] team = {
            new FullTimeEmployee("김자바", "E001", 5000000, 0.1),
            new ContractEmployee("이스프링", "E002", 30000, 160),
            new FullTimeEmployee("박부트", "E003", 6000000, 0.15)
        };

        processPayroll(team);
        // 김자바: 5500000.0원     (연봉 × 1.1)
        // 이스프링: 4800000.0원   (시급 × 시간)
        // 박부트: 6900000.0원     (연봉 × 1.15)
        // 총 급여: 17200000.0원
    }
}

