public interface MathUtils {
    // static 메서드 (Java 8+): 인터페이스 이름으로 직접 호출
    static int max(int a, int b) {
        return a > b ? a : b;
    }

    // private 메서드 (Java 9+): 내부에서만 사용, 중복 코드 제거
    default void logInfo(String msg) {
        log("INFO", msg);
    }

    default void logError(String msg) {
        log("ERROR", msg);
    }

    private void log(String level, String msg) {   // 공통 로직
        System.out.println("[" + level + "] " + msg);
    }
}

