public interface Sortable {
    void sort();
}

public interface Searchable {
    String search(String keyword);
}

public class DataProcessor implements Sortable, Searchable {
    private String[] data;

    public DataProcessor(String[] data) {
        this.data = data;
    }

    @Override
    public void sort() {
        java.util.Arrays.sort(data);
    }

    @Override
    public String search(String keyword) {
        for (String item : data) {
            if (item.contains(keyword)) return item;
        }
        return null;
    }

    public void process() {
        sort();
        System.out.println("데이터 처리 완료: " + java.util.Arrays.toString(data));
    }
}

