public class UserService {
    public UserResponse getUser(Long id) {
        return userRepository.findById(id)             // Optional<User>
            .map(user -> new UserResponse(              // User → UserResponse 변환
                user.getName(),
                user.getEmail()
            ))
            .orElseThrow(() -> new UserNotFoundException(id));  // 없으면 예외
    }

    public List<UserResponse> getActiveUsers() {
        return userRepository.findAll().stream()        // Stream<User>
            .filter(User::isActive)                     // 활성 사용자만
            .map(UserResponse::from)                    // DTO 변환
            .sorted(Comparator.comparing(UserResponse::getName))  // 이름순 정렬
            .toList();                                  // List 수집
    }
}

