public void cancelOrder(Order order) {
    if (!order.getStatus().isCancellable()) {
        throw new IllegalStateException(
            "현재 상태에서는 취소할 수 없습니다: " + order.getStatus().getDescription()
        );
    }
    order.setStatus(OrderStatus.CANCELLED);
}

