public class Counter {
    private int count = 0;

    // 메서드 동기화: 이 메서드는 한 번에 하나의 스레드만 실행
    public synchronized void increment() {
        count++;
    }

    // 블록 동기화: 특정 구간만 잠금
    public void incrementV2() {
        synchronized (this) {
            count++;
        }
    }

    public int getCount() {
        return count;
    }
}
