public interface PaymentGateway {
    PaymentResult pay(PaymentRequest request);
}

@Component("kakao")
public class KakaoPayGateway implements PaymentGateway { ... }

@Component("toss")
@Primary
public class TossPayGateway implements PaymentGateway { ... }

@Component("naver")
public class NaverPayGateway implements PaymentGateway { ... }

@Service
public class PaymentService {
    private final Map<String, PaymentGateway> gateways;

    // 모든 구현체를 Map으로 주입: {kakao=..., toss=..., naver=...}
    public PaymentService(Map<String, PaymentGateway> gateways) {
        this.gateways = gateways;
    }

    public PaymentResult processPayment(String method, PaymentRequest request) {
        PaymentGateway gateway = gateways.get(method);
        if (gateway == null) {
            throw new IllegalArgumentException("지원하지 않는 결제 수단: " + method);
        }
        return gateway.pay(request);
    }
}

