public class UserResponse {
    private Long id;
    private String name;
    private String email;
    private int age;
    private LocalDateTime createdAt;

    // Entity → DTO 변환 메서드
    public static UserResponse from(User user) {
        UserResponse response = new UserResponse();
        response.id = user.getId();
        response.name = user.getName();
        response.email = user.getEmail();
        response.age = user.getAge();
        response.createdAt = user.getCreatedAt();
        return response;
    }
}

public class UserResponse {
    private Long id;

    @JsonProperty("user_name")           // JSON 키 이름 지정
    private String name;

    @JsonIgnore                           // JSON에서 제외
    private String internalCode;

    @JsonFormat(pattern = "yyyy-MM-dd HH:mm:ss")  // 날짜 포맷
    private LocalDateTime createdAt;
}

// 결과 JSON:
// {"id": 1, "user_name": "김자바", "createdAt": "2024-01-15 10:30:00"}
// internalCode는 제외됨

@RestController
@RequestMapping("/api/users")
public class UserController {

    @GetMapping("/{id}")
    public ResponseEntity<UserResponse> getUser(@PathVariable Long id) {
        UserResponse user = userService.findById(id);
        return ResponseEntity.ok(user);   // 200 OK + Body
    }

    @PostMapping
    public ResponseEntity<UserResponse> createUser(@RequestBody UserCreateRequest request) {
        UserResponse created = userService.create(request);
        URI location = URI.create("/api/users/" + created.getId());
        return ResponseEntity
                .created(location)         // 201 Created + Location 헤더
                .body(created);
    }

