// 사용 예시
@Service
public class UserService {
    private final UserRepository userRepository;

    public UserService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    // 생성
    public User create(String name, String email, int age) {
        User user = new User(name, email, age);
        return userRepository.save(user);       // INSERT
    }

    // 단건 조회
    public User findById(Long id) {
        return userRepository.findById(id)       // SELECT ... WHERE id = ?
                .orElseThrow(() -> new RuntimeException("사용자 없음: " + id));
    }

    // 전체 조회
    public List<User> findAll() {
        return userRepository.findAll();         // SELECT *
    }

    // 수정 (변경 감지)
    @Transactional
    public User update(Long id, String name, int age) {
        User user = userRepository.findById(id)
                .orElseThrow(() -> new RuntimeException("사용자 없음"));
        user.updateProfile(name, age);           // 객체만 수정하면 UPDATE 자동 실행!
        return user;
    }

    // 삭제
    public void delete(Long id) {
        userRepository.deleteById(id);           // DELETE ... WHERE id = ?
    }
}

