public enum ErrorCode {
    // 공통
    INVALID_INPUT(400, "C001", "입력값이 유효하지 않습니다."),
    RESOURCE_NOT_FOUND(404, "C002", "요청한 리소스를 찾을 수 없습니다."),
    INTERNAL_ERROR(500, "C003", "서버 내부 오류가 발생했습니다."),

    // 사용자
    USER_NOT_FOUND(404, "U001", "사용자를 찾을 수 없습니다."),
    DUPLICATE_EMAIL(409, "U002", "이미 사용 중인 이메일입니다."),

    // 게시글
    POST_NOT_FOUND(404, "P001", "게시글을 찾을 수 없습니다."),

    // 주문
    ORDER_NOT_FOUND(404, "O001", "주문을 찾을 수 없습니다."),
    INSUFFICIENT_STOCK(400, "O002", "재고가 부족합니다.");

    private final int status;
    private final String code;
    private final String message;

    ErrorCode(int status, String code, String message) {
        this.status = status;
        this.code = code;
        this.message = message;
    }

    public int getStatus() { return status; }
    public String getCode() { return code; }
    public String getMessage() { return message; }
}

public class ErrorResponse {
    private int status;
    private String code;
    private String message;
    private List<FieldError> errors;

    public static ErrorResponse of(ErrorCode errorCode) {
        ErrorResponse response = new ErrorResponse();
        response.status = errorCode.getStatus();
        response.code = errorCode.getCode();
        response.message = errorCode.getMessage();
        response.errors = new ArrayList<>();
        return response;
    }

    public static ErrorResponse of(ErrorCode errorCode, String detail) {
        ErrorResponse response = of(errorCode);
        response.message = detail;
        return response;
    }

    public static ErrorResponse of(ErrorCode errorCode, List<FieldError> fieldErrors) {
        ErrorResponse response = of(errorCode);
        response.errors = fieldErrors;
        return response;
    }

    // getter
    public int getStatus() { return status; }
    public String getCode() { return code; }
    public String getMessage() { return message; }
    public List<FieldError> getErrors() { return errors; }

    // 필드 에러 (Validation 실패 시)
    public static class FieldError {
        private String field;
        private String value;
        private String reason;

        public FieldError(String field, String value, String reason) {
            this.field = field;
            this.value = value;
            this.reason = reason;
        }

        public String getField() { return field; }
        public String getValue() { return value; }
        public String getReason() { return reason; }
    }
}

public class BusinessException extends RuntimeException {
    private final ErrorCode errorCode;

    public BusinessException(ErrorCode errorCode) {
        super(errorCode.getMessage());
        this.errorCode = errorCode;
    }

    public BusinessException(ErrorCode errorCode, String detail) {
        super(detail);
        this.errorCode = errorCode;
    }

    public ErrorCode getErrorCode() { return errorCode; }
}

