@RestControllerAdvice
public class GlobalExceptionHandler {

    // 비즈니스 예외 (개발자가 의도적으로 던진 예외)
    @ExceptionHandler(BusinessException.class)
    public ResponseEntity<ErrorResponse> handleBusinessException(BusinessException e) {
        ErrorCode code = e.getErrorCode();
        ErrorResponse response = ErrorResponse.of(code, e.getMessage());
        return ResponseEntity.status(code.getStatus()).body(response);
    }

    // Validation 예외 (Step 29에서 상세)
    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<ErrorResponse> handleValidationException(
            MethodArgumentNotValidException e) {
        List<ErrorResponse.FieldError> fieldErrors = e.getBindingResult()
                .getFieldErrors().stream()
                .map(error -> new ErrorResponse.FieldError(
                        error.getField(),
                        error.getRejectedValue() != null ? error.getRejectedValue().toString() : "",
                        error.getDefaultMessage()
                ))
                .toList();
        ErrorResponse response = ErrorResponse.of(ErrorCode.INVALID_INPUT, fieldErrors);
        return ResponseEntity.badRequest().body(response);
    }

    // 그 외 모든 예외 (예상치 못한 서버 에러)
    @ExceptionHandler(Exception.class)
    public ResponseEntity<ErrorResponse> handleException(Exception e) {
        ErrorResponse response = ErrorResponse.of(ErrorCode.INTERNAL_ERROR);
        return ResponseEntity.internalServerError().body(response);
    }
}

@Service
public class PostService {

    @Transactional
    public PostResponse findById(Long id) {
        Post post = postRepository.findById(id)
                .orElseThrow(() -> new PostNotFoundException(id));  // → 404
        post.increaseViewCount();
        return PostResponse.from(post);
    }

    @Transactional
    public PostResponse create(PostCreateRequest request) {
        if (postRepository.existsByTitle(request.getTitle())) {
            throw new BusinessException(ErrorCode.INVALID_INPUT, "이미 존재하는 제목입니다.");  // → 400
        }
        Post post = Post.create(request.getTitle(), request.getContent(), request.getAuthor());
        postRepository.save(post);
        return PostResponse.from(post);
    }
}

