@Configuration
public class QueryDslConfig {

    @Bean
    public JPAQueryFactory jpaQueryFactory(EntityManager entityManager) {
        return new JPAQueryFactory(entityManager);
    }
}

@Repository
public class PostQueryRepository {

    private final JPAQueryFactory queryFactory;

    public PostQueryRepository(JPAQueryFactory queryFactory) {
        this.queryFactory = queryFactory;
    }

    // 전체 조회
    public List<Post> findAll() {
        QPost post = QPost.post;

        return queryFactory
                .selectFrom(post)
                .orderBy(post.createdAt.desc())
                .fetch();
    }

    // 조건 조회
    public List<Post> findByAuthor(String author) {
        QPost post = QPost.post;

        return queryFactory
                .selectFrom(post)
                .where(post.author.eq(author))
                .orderBy(post.createdAt.desc())
                .fetch();
    }

    // JOIN + 조건
    public List<Post> findPostsByUserName(String userName) {
        QPost post = QPost.post;
        QUser user = QUser.user;

        return queryFactory
                .selectFrom(post)
                .join(post.user, user).fetchJoin()   // fetch join
                .where(user.name.eq(userName))
                .fetch();
    }
}

@Repository
public class PostQueryRepository {

    private final JPAQueryFactory queryFactory;

    public PostQueryRepository(JPAQueryFactory queryFactory) {
        this.queryFactory = queryFactory;
    }

    // 동적 검색
    public List<Post> search(PostSearchCondition condition) {
        QPost post = QPost.post;

        return queryFactory
                .selectFrom(post)
                .where(
                    titleContains(condition.getKeyword()),
                    authorEq(condition.getAuthor()),
                    viewCountGoe(condition.getMinViews()),
                    createdAfter(condition.getStartDate())
                )
                .orderBy(post.createdAt.desc())
                .fetch();
    }

    // 각 조건을 BooleanExpression으로 분리
    private BooleanExpression titleContains(String keyword) {
        return keyword != null ? QPost.post.title.contains(keyword) : null;
    }

    private BooleanExpression authorEq(String author) {
        return author != null ? QPost.post.author.eq(author) : null;
    }

    private BooleanExpression viewCountGoe(Integer minViews) {
        return minViews != null ? QPost.post.viewCount.goe(minViews) : null;
    }

    private BooleanExpression createdAfter(LocalDateTime startDate) {
        return startDate != null ? QPost.post.createdAt.after(startDate) : null;
    }
}

// where()에 null이 전달되면 해당 조건은 무시됨!
.where(
    titleContains("Java"),     // "Java" → post.title LIKE '%Java%'
    authorEq(null),            // null → 조건 없음 (무시)
    viewCountGoe(100),         // 100 → post.view_count >= 100
    createdAfter(null)         // null → 조건 없음 (무시)
)

