public class PostSearchCondition {
    private String keyword;
    private String author;
    private Integer minViews;
    private LocalDateTime startDate;

    // getter, setter
}

public Page<Post> searchWithPaging(PostSearchCondition condition, Pageable pageable) {
    QPost post = QPost.post;

    List<Post> content = queryFactory
            .selectFrom(post)
            .where(
                titleContains(condition.getKeyword()),
                authorEq(condition.getAuthor())
            )
            .orderBy(post.createdAt.desc())
            .offset(pageable.getOffset())
            .limit(pageable.getPageSize())
            .fetch();

    Long total = queryFactory
            .select(post.count())
            .from(post)
            .where(
                titleContains(condition.getKeyword()),
                authorEq(condition.getAuthor())
            )
            .fetchOne();

    return new PageImpl<>(content, pageable, total != null ? total : 0);
}

// Projections.constructor로 DTO 직접 조회
public List<PostListResponse> findPostList() {
    QPost post = QPost.post;
    QUser user = QUser.user;

    return queryFactory
            .select(Projections.constructor(PostListResponse.class,
                    post.id,
                    post.title,
                    user.name,
                    post.viewCount,
                    post.createdAt
            ))
            .from(post)
            .join(post.user, user)
            .orderBy(post.createdAt.desc())
            .fetch();
}

