public List<Product> search(ProductSearchCondition cond) {
    QProduct product = QProduct.product;

    return queryFactory
            .selectFrom(product)
            .where(
                nameContains(cond.getKeyword()),
                categoryEq(cond.getCategory()),
                priceGoe(cond.getMinPrice()),
                priceLoe(cond.getMaxPrice())
            )
            .orderBy(product.createdAt.desc())
            .fetch();
}

private BooleanExpression nameContains(String keyword) {
    return keyword != null ? QProduct.product.name.contains(keyword) : null;
}
private BooleanExpression categoryEq(String category) {
    return category != null ? QProduct.product.category.eq(category) : null;
}
private BooleanExpression priceGoe(Integer minPrice) {
    return minPrice != null ? QProduct.product.price.goe(minPrice) : null;
}
private BooleanExpression priceLoe(Integer maxPrice) {
    return maxPrice != null ? QProduct.product.price.loe(maxPrice) : null;
}

