// 컨텍스트: 전략을 사용하는 Service
@Service
public class OrderService {
    private final Map<String, DiscountPolicy> policies;

    public OrderService(List<DiscountPolicy> policyList) {
        this.policies = policyList.stream()
                .collect(Collectors.toMap(DiscountPolicy::getPolicyName, p -> p));
    }

    public int calculateFinalPrice(String policyName, int price) {
        DiscountPolicy policy = policies.get(policyName);
        if (policy == null) throw new IllegalArgumentException("Unknown policy: " + policyName);
        int discount = policy.calculateDiscount(price);
        return price - discount;
    }
}

// 추상 클래스: 알고리즘 뼈대 정의
public abstract class AbstractDataExporter {

    // 템플릿 메서드: 전체 흐름을 정의 (final로 변경 금지)
    public final void export(Long userId) {
        List<?> data = fetchData(userId);       // [1] 데이터 조회 (변하는 부분)
        String formatted = format(data);         // [2] 포맷 변환 (변하는 부분)
        send(formatted, userId);                 // [3] 전송 (변하는 부분)
        log(userId);                             // [4] 로깅 (고정 부분)
    }

    // 변하는 부분: 하위 클래스가 구현
    protected abstract List<?> fetchData(Long userId);
    protected abstract String format(List<?> data);
    protected abstract void send(String data, Long userId);

    // 고정 부분: 공통 로직
    private void log(Long userId) {
        System.out.println("데이터 내보내기 완료 - userId=" + userId);
    }
}

