@Component
public class JwtTokenProvider {
    private final SecretKey key;
    private final long expiration;

    public JwtTokenProvider(
            @Value("${jwt.secret}") String secret,
            @Value("${jwt.expiration}") long expiration) {
        this.key = Keys.hmacShaKeyFor(Decoders.BASE64.decode(secret));
        this.expiration = expiration;
    }

    // 토큰 생성
    public String createToken(String email, String role) {
        Date now = new Date();
        return Jwts.builder()
                .subject(email)
                .claim("role", role)
                .issuedAt(now)
                .expiration(new Date(now.getTime() + expiration))
                .signWith(key)
                .compact();
    }

    // 토큰에서 이메일 추출
    public String getEmail(String token) {
        return parseClaims(token).getSubject();
    }

    // 토큰 유효성 검증
    public boolean validateToken(String token) {
        try {
            parseClaims(token);
            return true;
        } catch (JwtException | IllegalArgumentException e) {
            return false;
        }
    }

    private Claims parseClaims(String token) {
        return Jwts.parser().verifyWith(key).build()
                .parseSignedClaims(token).getPayload();
    }
}

@Component
public class JwtAuthenticationFilter extends OncePerRequestFilter {
    private final JwtTokenProvider tokenProvider;
    private final CustomUserDetailsService userDetailsService;

    // 생성자 주입 생략

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                     HttpServletResponse response,
                                     FilterChain chain) throws ServletException, IOException {
        String token = resolveToken(request);

        if (token != null && tokenProvider.validateToken(token)) {
            String email = tokenProvider.getEmail(token);
            UserDetails userDetails = userDetailsService.loadUserByUsername(email);
            UsernamePasswordAuthenticationToken auth =
                    new UsernamePasswordAuthenticationToken(userDetails, null, userDetails.getAuthorities());
            SecurityContextHolder.getContext().setAuthentication(auth);
        }

        chain.doFilter(request, response);
    }

    private String resolveToken(HttpServletRequest request) {
        String bearer = request.getHeader("Authorization");
        if (bearer != null && bearer.startsWith("Bearer ")) {
            return bearer.substring(7);
        }
        return null;
    }
}

@Service
@Transactional(readOnly = true)
public class PostService {
    private final PostRepository postRepository;
    private final PostQueryRepository postQueryRepository;
    private final UserRepository userRepository;

    // 생성
    @Transactional
    public PostResponse create(PostCreateRequest request, Long userId) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new BusinessException(ErrorCode.USER_NOT_FOUND));
        Post post = Post.create(request.getTitle(), request.getContent(), user);
        postRepository.save(post);
        return PostResponse.from(post);
    }

    // 단건 조회 (조회수 증가)
    @Transactional
    public PostDetailResponse findById(Long id) {
        Post post = postRepository.findById(id)
                .orElseThrow(() -> new BusinessException(ErrorCode.POST_NOT_FOUND));
        post.increaseViewCount();
        return PostDetailResponse.from(post);
    }

    // 검색 + 페이징 (QueryDSL)
    public Page<PostResponse> search(PostSearchCondition condition, Pageable pageable) {
        return postQueryRepository.search(condition, pageable)
                .map(PostResponse::from);
    }

    // 수정 (본인만)
    @Transactional
    public PostResponse update(Long id, PostUpdateRequest request, Long userId) {
        Post post = postRepository.findById(id)
                .orElseThrow(() -> new BusinessException(ErrorCode.POST_NOT_FOUND));
        validateOwner(post.getUser().getId(), userId);
        post.update(request.getTitle(), request.getContent());
        return PostResponse.from(post);
    }

    // 삭제 (본인 또는 ADMIN)
    @Transactional
    public void delete(Long id, Long userId, String role) {
        Post post = postRepository.findById(id)
                .orElseThrow(() -> new BusinessException(ErrorCode.POST_NOT_FOUND));
        if (!"ADMIN".equals(role)) {
            validateOwner(post.getUser().getId(), userId);
        }
        postRepository.delete(post);
    }

    private void validateOwner(Long ownerId, Long currentUserId) {
        if (!ownerId.equals(currentUserId)) {
            throw new BusinessException(ErrorCode.FORBIDDEN, "권한이 없습니다.");
        }
    }
}

@PostMapping
public ResponseEntity<ApiResponse<PostResponse>> create(
        @Valid @RequestBody PostCreateRequest request,
        @AuthenticationPrincipal UserDetails userDetails) {
    Long userId = getUserId(userDetails);
    PostResponse response = postService.create(request, userId);
    return ResponseEntity.status(HttpStatus.CREATED)
            .body(ApiResponse.created(response));
}

@Service
@Transactional(readOnly = true)
public class CommentService {
    private final CommentRepository commentRepository;
    private final PostRepository postRepository;
    private final UserRepository userRepository;

    @Transactional
    public CommentResponse create(Long postId, CommentCreateRequest request, Long userId) {
        Post post = postRepository.findById(postId)
                .orElseThrow(() -> new BusinessException(ErrorCode.POST_NOT_FOUND));
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new BusinessException(ErrorCode.USER_NOT_FOUND));

        Comment comment = Comment.create(request.getContent(), post, user);
        commentRepository.save(comment);
        return CommentResponse.from(comment);
    }

    public List<CommentResponse> findByPostId(Long postId) {
        return commentRepository.findByPostIdOrderByCreatedAtAsc(postId)
                .stream()
                .map(CommentResponse::from)
                .toList();
    }

    @Transactional
    public void delete(Long commentId, Long userId, String role) {
        Comment comment = commentRepository.findById(commentId)
                .orElseThrow(() -> new BusinessException(ErrorCode.COMMENT_NOT_FOUND));
        if (!"ADMIN".equals(role)) {
            validateOwner(comment.getUser().getId(), userId);
        }
        commentRepository.delete(comment);
    }
}

@RestController
@RequestMapping("/api/files")
public class FileController {

    @Value("${file.upload-dir}")
    private String uploadDir;

    @PostMapping
    public ResponseEntity<Map<String, String>> upload(@RequestParam("file") MultipartFile file) {
        String filename = UUID.randomUUID() + "_" + file.getOriginalFilename();
        Path path = Paths.get(uploadDir, filename);
        Files.createDirectories(path.getParent());
        file.transferTo(path.toFile());

        String url = "/uploads/" + filename;
        return ResponseEntity.ok(Map.of("url", url));
    }
}

@ExtendWith(MockitoExtension.class)    // Mockito 활성화
class PostServiceTest {

    @InjectMocks                        // 테스트 대상
    private PostService postService;

    @Mock                               // 가짜 객체
    private PostRepository postRepository;

    @Mock
    private UserRepository userRepository;

    @Test
    @DisplayName("게시글 생성 성공")
    void createPost_success() {
        // given (준비)
        Long userId = 1L;
        User user = User.builder().name("김자바").email("j@m.com").build();
        PostCreateRequest request = new PostCreateRequest("제목", "내용");

        when(userRepository.findById(userId)).thenReturn(Optional.of(user));
        when(postRepository.save(any(Post.class))).thenAnswer(invocation -> {
            Post post = invocation.getArgument(0);
            // id를 설정하는 리플렉션 또는 테스트용 빌더
            return post;
        });

        // when (실행)
        PostResponse response = postService.create(request, userId);

        // then (검증)
        assertThat(response.getTitle()).isEqualTo("제목");
        assertThat(response.getContent()).isEqualTo("내용");
        verify(postRepository, times(1)).save(any(Post.class));
        verify(userRepository, times(1)).findById(userId);
    }

    @Test
    @DisplayName("존재하지 않는 게시글 조회 시 예외 발생")
    void findById_notFound() {
        // given
        when(postRepository.findById(999L)).thenReturn(Optional.empty());

        // when & then
        assertThatThrownBy(() -> postService.findById(999L))
                .isInstanceOf(BusinessException.class)
                .hasMessageContaining("게시글을 찾을 수 없습니다");
    }

    @Test
    @DisplayName("본인이 아닌 사용자의 게시글 수정 시 예외 발생")
    void updatePost_forbidden() {
        // given
        Long postId = 1L;
        Long ownerId = 1L;
        Long otherUserId = 2L;

        User owner = User.builder().name("작성자").build();
        Post post = Post.create("제목", "내용", owner);
        // owner의 id를 1L로 설정 (리플렉션 또는 테스트 유틸)

        when(postRepository.findById(postId)).thenReturn(Optional.of(post));

        PostUpdateRequest request = new PostUpdateRequest("수정", null);

        // when & then
        assertThatThrownBy(() -> postService.update(postId, request, otherUserId))
                .isInstanceOf(BusinessException.class);
    }
}

